import { Link, useNavigate, useLocation } from "react-router-dom";
import { useState, useEffect } from "react";
import { toast } from "react-toastify";
import SearchModal from "./SearchModal";

export default function Navbar({ authState, setAuthState }) {
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [activeMenu, setActiveMenu] = useState(null);

  const navigate = useNavigate();
  const location = useLocation();

  const currentUser = authState?.currentUser;

  // Keyboard shortcut Ctrl+K
  useEffect(() => {
    const handleKeyDown = (e) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 'k') {
        e.preventDefault();
        setIsSearchOpen(true);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  useEffect(() => {
    const handleAuthChange = () => {
      const user = localStorage.getItem("currentUser");
      const token = localStorage.getItem("authToken");
      if (setAuthState) {
        setAuthState({
          isAuthenticated: !!(user && token),
          currentUser: user ? JSON.parse(user) : null
        });
      }
    };

    window.addEventListener('authChange', handleAuthChange);
    window.addEventListener('storage', handleAuthChange);

    return () => {
      window.removeEventListener('authChange', handleAuthChange);
      window.removeEventListener('storage', handleAuthChange);
    };
  }, [setAuthState]);

  const handleLogout = () => {
    localStorage.removeItem("currentUser");
    localStorage.removeItem("authToken");
    setIsUserMenuOpen(false);

    if (setAuthState) {
      setAuthState({
        isAuthenticated: false,
        currentUser: null
      });
    }
    window.dispatchEvent(new Event('authChange'));
    toast.success("Logged out successfully!");
    navigate("/");
  };

  const isActive = (path) => location.pathname === path;

  return (
    <>
      <nav className="bg-white text-text-dark h-18 shadow-sm sticky top-0 z-[60] border-b border-gray-100">
        <div className="container mx-auto px-4 lg:px-12 h-full flex items-center justify-between">

          {/* Left: Logo and Nav Links */}
          <div className="flex items-center h-full">
            <Link to="/" className="flex items-center mr-10">
              <img src="https://groww.in/logo-groww-rect.svg" alt="Groww" className="h-8 w-auto" />
            </Link>

            <div className="hidden md:flex h-full items-center space-x-2">
              <div
                className="h-full flex items-center px-4 relative cursor-pointer"
                onMouseEnter={() => setActiveMenu('stocks')}
                onMouseLeave={() => setActiveMenu(null)}
              >
                <Link to="/markets" className={`font-semibold text-sm transition-colors ${isActive('/markets') ? 'text-primary' : 'text-text-dark hover:text-primary'}`}>
                  Stocks
                </Link>
                {isActive('/markets') && <div className="absolute bottom-0 left-0 right-0 h-1 bg-primary rounded-t-full"></div>}

                {/* Mega Menu Stocks */}
                {activeMenu === 'stocks' && (
                  <div className="absolute top-[72px] left-0 w-[450px] bg-white shadow-2xl rounded-b-2xl border border-gray-100 animate-slide-down p-6 z-[70]">
                    <div className="grid grid-cols-2 gap-8">
                      <div>
                        <h4 className="text-[10px] font-bold text-text-light uppercase tracking-widest mb-4">Invest</h4>
                        <ul className="space-y-3">
                          <li><Link to="/markets" className="text-sm font-medium text-text-dark hover:text-primary flex items-center"><span className="mr-2">📈</span> Market Indices</Link></li>
                          <li><Link to="/markets" className="text-sm font-medium text-text-dark hover:text-primary flex items-center"><span className="mr-2">🔝</span> Top Gainers</Link></li>
                          <li><Link to="/watchlist" className="text-sm font-medium text-text-dark hover:text-primary flex items-center"><span className="mr-2">⭐</span> My Watchlist</Link></li>
                        </ul>
                      </div>
                      <div>
                        <h4 className="text-[10px] font-bold text-text-light uppercase tracking-widest mb-4">Trading</h4>
                        <ul className="space-y-3">
                          <li><span className="text-sm font-medium text-text-dark hover:text-primary cursor-pointer flex items-center"><span className="mr-2">📊</span> F&O</span></li>
                          <li><span className="text-sm font-medium text-text-dark hover:text-primary cursor-pointer flex items-center"><span className="mr-2">📉</span> Intraday</span></li>
                        </ul>
                      </div>
                    </div>
                  </div>
                )}
              </div>

              <div className="h-full flex items-center px-4 relative cursor-pointer group">
                <span className="font-semibold text-sm text-text-dark group-hover:text-primary transition-colors">Mutual Funds</span>
              </div>

              <div className="h-full flex items-center px-4 relative cursor-pointer group">
                <span className="font-semibold text-sm text-text-dark group-hover:text-primary transition-colors">US Stocks</span>
              </div>
            </div>
          </div>

          {/* Center: Search Field (Groww Style) */}
          <div className="hidden lg:flex flex-1 max-w-xl mx-8">
            <div
              className="w-full flex items-center bg-gray-50 border border-gray-100 hover:bg-white hover:border-gray-200 hover:shadow-md transition-all rounded-lg px-4 py-2.5 cursor-text text-gray-400 group"
              onClick={() => setIsSearchOpen(true)}
            >
              <svg className="w-5 h-5 mr-3 group-hover:text-primary transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
              </svg>
              <span className="text-sm flex-1">What are you looking for today?</span>
              <kbd className="hidden sm:inline-flex items-center px-1.5 py-0.5 text-[10px] font-bold text-gray-400 bg-white border border-gray-200 rounded shadow-sm">
                Ctrl K
              </kbd>
            </div>
          </div>

          {/* Right: Actions */}
          <div className="flex items-center space-x-4">
            <button className="lg:hidden p-2 text-text-dark" onClick={() => setIsSearchOpen(true)}>
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
              </svg>
            </button>

            {currentUser ? (
              <div className="relative">
                <button
                  onClick={() => setIsUserMenuOpen(!isUserMenuOpen)}
                  className="flex items-center space-x-2 p-1 rounded-full hover:bg-gray-100 transition-colors"
                >
                  <div className="w-9 h-9 bg-primary text-white rounded-full flex items-center justify-center font-bold text-sm shadow-sm">
                    {currentUser.name ? currentUser.name.charAt(0).toUpperCase() : "U"}
                  </div>
                </button>

                {isUserMenuOpen && (
                  <div className="absolute right-0 mt-3 w-72 bg-white rounded-2xl shadow-2xl border border-gray-100 py-4 animate-scale-in z-[80]">
                    <div className="px-6 pb-4 border-b border-gray-50">
                      <p className="font-bold text-text-dark">{currentUser.name}</p>
                      <p className="text-xs text-text-light">{currentUser.email}</p>
                    </div>

                    <div className="py-2">
                      <Link to="/dashboard" onClick={() => setIsUserMenuOpen(false)} className="flex items-center px-6 py-3 text-sm font-medium text-text-dark hover:bg-gray-50 hover:text-primary transition-all">
                        <span className="mr-3">📊</span> Dashboard
                      </Link>
                      <Link to="/portfolio" onClick={() => setIsUserMenuOpen(false)} className="flex items-center px-6 py-3 text-sm font-medium text-text-dark hover:bg-gray-50 hover:text-primary transition-all">
                        <span className="mr-3">💼</span> My Portfolio
                      </Link>
                      <Link to="/watchlist" onClick={() => setIsUserMenuOpen(false)} className="flex items-center px-6 py-3 text-sm font-medium text-text-dark hover:bg-gray-50 hover:text-primary transition-all">
                        <span className="mr-3">⭐</span> Watchlist
                      </Link>
                      <Link to="/wallet" onClick={() => setIsUserMenuOpen(false)} className="flex items-center px-6 py-3 text-sm font-medium text-text-dark hover:bg-gray-50 hover:text-primary transition-all border-t border-gray-50 mt-2">
                        <span className="mr-3">💰</span> Wallet
                      </Link>
                      <Link to="/profile" onClick={() => setIsUserMenuOpen(false)} className="flex items-center px-6 py-3 text-sm font-medium text-text-dark hover:bg-gray-50 hover:text-primary transition-all">
                        <span className="mr-3">👤</span> Profile
                      </Link>
                    </div>

                    <div className="pt-2 border-t border-gray-50">
                      <button onClick={handleLogout} className="flex items-center w-full px-6 py-3 text-sm font-bold text-danger hover:bg-red-50 transition-all">
                        <span className="mr-3">🚪</span> Logout
                      </button>
                    </div>
                  </div>
                )}
              </div>
            ) : (
              <Link
                to="/login"
                className="bg-primary text-white px-8 py-2.5 rounded-lg hover:bg-primary-dark transition-all duration-300 font-bold text-sm shadow-lg shadow-primary/20 hover:shadow-primary/30"
              >
                Login / Register
              </Link>
            )}
          </div>
        </div>
      </nav>

      <SearchModal isOpen={isSearchOpen} onClose={() => setIsSearchOpen(false)} />
    </>
  );
}
